#include<bits/stdc++.h>
using namespace std;
const int N=300010,M=600030;
int n,m;
int head[N],head1[N],head2[N];
int tot,tot1,tot2;
int b1[M],b2[M];
int cnt[N];
int d[N],f[N][23],lg[N];
int s[N],t[N],dis[N],w[N];
struct edge
{
    int to,nxt;
}e[M],e1[M],e2[M];
void add(int x,int y)
{
    e[++tot]=(edge){y,head[x]};
    head[x]=tot;
}
void add1(int x,int y)
{
    e1[++tot1]=(edge){y,head1[x]};
    head1[x]=tot1;
}
void add2(int x,int y)
{
    e2[++tot2]=(edge){y,head2[x]};
    head2[x]=tot2;
}
void dfs(int x,int fa=0)
{
    d[x]=d[fa]+1;
    f[x][0]=fa;
    for(int i=1;(1<<i)<=d[x];i++)
    {
        f[x][i]=f[f[x][i-1]][i-1];
    }
    for(int i=head[x];i;i=e[i].nxt)
    {
        int v=e[i].to;
        if(v!=fa)
        {
            dfs(v,x);
        }
    }
}
int lca(int x,int y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=f[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(int i=lg[d[x]];i>=0;i--)
    {
        if(f[x][i]!=f[y][i])
        {
            x=f[x][i];
            y=f[y][i];
        }
    }
    return f[x][0];
}
long long ans[N];
void dfs2(int x,int fa=0)
{
    int t1=b1[w[x]+d[x]],t2=b2[w[x]-d[x]+N];
    for(int i=head[x];i;i=e[i].nxt)
    {
        int v=e[i].to;
        if(v!=fa)
        {
            dfs2(v,x);
        }
    }
    b1[d[x]]+=cnt[x];
    for(int i=head1[x];i;i=e1[i].nxt)
    {
        int v=e1[i].to;
        b2[dis[v]-d[t[v]]+N]++;
    }
    ans[x]+=(b1[w[x]+d[x]]-t1)+(b2[w[x]-d[x]+N]-t2);
    for(int i=head2[x];i;i=e2[i].nxt)
    {
        int v=e2[i].to;
        b1[d[s[v]]]--;
        b2[dis[v]-d[t[v]]+N]--;
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=2;i<=n;i++)
    {
        lg[i]=lg[i/2]+1;
    }
    for(int i=1;i<n;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        add(u,v);
        add(v,u);
    }
    dfs(1);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&w[i]);
    }
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d",&s[i],&t[i]);
        int l=lca(s[i],t[i]);
        cnt[s[i]]++;
        dis[i]=d[s[i]]+d[t[i]]-d[l]*2;
        if(d[l]+w[l]==d[s[i]])
        {
            ans[l]--;
        }
        add1(t[i],i);
        add2(l,i);
    }
    dfs2(1);
    for(int i=1;i<=n;i++)
    {
        printf("%lld ",ans[i]);
    }
    return 0;
}
